        d_mutex.lock();
        if (wait > 1) {
            // If we were the last reader and we could not transition
            // atomically, then there must be another trying to upgrade
            // atomically so signal it.
            d_signalState = e_UPGRADE_SIGNALED;
            d_upgradeCond.signal();
