                d_writeCond.wait(&d_mutex);
            }
            d_signalState = e_NOT_SIGNALED;
        }
        d_mutex.unlock();
    }

    if (!mine) {
        d_owner = me;
        d_owned = true;
    }

    return atomic ? 0 : 1;
}

